class Solution {
public:
    int distinctSequences(int n) {
        const int MOD = 1e9 + 7;
        vector<int> dp(6, 1);
        for (int i = 1; i < n; i++) {
            vector<int> ndp(6, 0);
            for (int j = 0; j < 6; j++) {
                for (int k = 0; k < 6; k++) {
                    if (__gcd(j, k) == 1 && (i == 1 || j != k || i - 2 < 0 || dp[k] == 0)) {
                        ndp[j] = (ndp[j] + dp[k]) % MOD;
                    }
                }
            }
            dp = ndp;
        }
        int res = 0;
        for (int i = 0; i < 6; i++) {
            res = (res + dp[i]) % MOD;
        }
        return res;
    }
};
